import{_ as l,P as t,I as r,g as o,j as h,l as s,d as e,k as n}from"./chunks/framework.CbuNJfvM.js";const p="/ghul-logo-draft.png",D=JSON.parse('{"title":"ghūl programming language","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),g={name:"index.md"};function c(d,i,k,u,m,y){const a=t("GhulExample");return r(),o("div",null,[i[0]||(i[0]=h('<h1 id="ghul-programming-language" tabindex="-1">ghūl programming language <a class="header-anchor" href="#ghul-programming-language" aria-label="Permalink to &quot;ghūl programming language&quot;">​</a></h1><p><img src="'+p+'" alt="ghūl programming language logo"></p><blockquote><ul><li>The ghūl language, compiler, tools, and this website are all very much a <strong>work-in-progress</strong>.</li><li>Whatever the <a href="https://github.com/degory/ghul" target="_blank" rel="noreferrer">ghūl compiler</a> accepts is currently the definitive ghūl language reference.</li><li>ghūl is pronounced &#39;ghoul&#39;.</li></ul></blockquote><h2 id="why-ghul" tabindex="-1">why ghūl? <a class="header-anchor" href="#why-ghul" aria-label="Permalink to &quot;why ghūl?&quot;">​</a></h2><p>Why not 🤔</p><p>ghūl is mainly an opportunity for <a href="https://github.com/degory" target="_blank" rel="noreferrer">me</a> to experiment with programming language design. Apart from a slightly quirky syntax, ghūl is a fairly conventional programming language. Although ghūl is a hobby project maintained by a single person, its goal is to be sufficiently expressive for general-purpose development: the <a href="https://github.com/degory/ghul" target="_blank" rel="noreferrer">ghūl compiler</a> itself is written in ghūl.</p><h2 id="features" tabindex="-1">features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;features&quot;">​</a></h2><ul><li><p><strong>type safety</strong>: ghūl enforces type safety at compile-time.</p></li><li><p><strong>type inference</strong>: local variables, loop variables, destructured variables, anonymous function parameter and return types, and generic type arguments at call sites are inferred from initializers and use sites. Inference is bidirectional and iterative within a function body.</p></li><li><p><strong>type narrowing</strong>: union variant tests, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">isa</span></code> checks, null checks, and <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">if</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> let</span></code> narrow a local variable&#39;s type within the code the check covers.</p></li><li><p><strong>functional programming</strong>: first-class anonymous functions with closures, higher order functions, and non-mutating pipe operations over lists. Arrays, tuples, and list literals are immutable.</p></li><li><p><strong>pattern matching</strong>: <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">if</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> let</span></code> and <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">case</span></code>/<code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">when</span></code> arms with type tests, destructuring with literal leaves, and value lists. <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">case</span></code> arms over a union or <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">bool</span></code> are checked for exhaustiveness; other scrutinees need <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">else</span></code>.</p></li><li><p><strong>expression-oriented</strong>: <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">if</span></code>, <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">case</span></code>, and block forms are expressions.</p></li><li><p><strong>OOP</strong>: classes, structs, traits, inheritance, polymorphism, properties, and indexers.</p></li><li><p><strong>error handling</strong>: <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">try</span></code>/<code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">catch</span></code>/<code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">finally</span></code> over .NET exceptions.</p></li><li><p><strong>generics</strong>: types, methods, and functions can have generic type parameters. Traits can be declared covariant or contravariant with <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> out</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> / <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;"> in</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code>; variance on imported .NET generics is read from metadata.</p></li><li><p><strong>async/await</strong>: functions returning <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Tasks</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">TASK</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> can use <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">await</span></code> to wait on a task and resume with its result.</p></li><li><p><strong>generators</strong>: functions returning <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Iterable</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> can use <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">yield</span></code> to produce a sequence of values lazily.</p></li><li><p><strong>.NET integration</strong>: ghūl targets .NET, producing and consuming NuGet packages and inter-operating with other .NET languages.</p></li></ul><h2 id="examples" tabindex="-1">examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;examples&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">interactive examples</p><p>Hover any identifier in a code example to see its type. An example&#39;s output and any compiler diagnostics appear in a panel beneath it.</p></div><h3 id="hello-world" tabindex="-1">hello world! <a class="header-anchor" href="#hello-world" aria-label="Permalink to &quot;hello world!&quot;">​</a></h3>',11)),s(a,{name:"hello-world"}),i[1]||(i[1]=e("h3",{id:"functional",tabindex:"-1"},[n("functional "),e("a",{class:"header-anchor",href:"#functional","aria-label":'Permalink to "functional"'},"​")],-1)),s(a,{name:"functional"}),i[2]||(i[2]=e("h3",{id:"oop",tabindex:"-1"},[n("OOP "),e("a",{class:"header-anchor",href:"#oop","aria-label":'Permalink to "OOP"'},"​")],-1)),s(a,{name:"object-oriented"})])}const C=l(g,[["render",c]]);export{D as __pageData,C as default};
